import { SsoEntity } from './sso-entity';
/**
 * Envelope object for a list of recipients.
 */
export interface DirectShareRecipientList {
    recipients: SsoEntity[];
    /**
     * Use this as page-key query param to get the next page
     */
    nextPageKey?: string;
    /**
     * Total number of recipients of the share.
     */
    totalCount: number;
}
